// ========================================
// VALIDADOR DE CATEGORÍAS - SOCIALMASK
// Asegura que el agente clasificador devuelva solo una categoría válida
// ========================================

// Obtener la respuesta del agente clasificador
const respuestaAgente = $input.first().json.output || 
                        $input.first().json.response || 
                        $input.first().json.text || 
                        $input.first().json.clasificacion ||
                        '';

// Categorías válidas permitidas (exactamente como las definiste)
const categoriasValidas = [
  'agendar_cita',
  'cancelar_cita',
  'posponer_cita',
  'reagendar_cita',
  'conocer_servicios',
  'comprar',
  'asesoria_de_ventas'
];

// Limpiar y normalizar la respuesta del agente
// Convierte a minúsculas y elimina espacios, puntos, comillas, etc.
let respuestaLimpia = respuestaAgente
  .toLowerCase()
  .trim()
  .replace(/[^a-záéíóúñ_]/g, ''); // Mantiene letras y guión bajo

// Buscar si alguna categoría válida está en la respuesta
let categoriaFinal = null;

for (const categoria of categoriasValidas) {
  // Eliminar guiones bajos para comparación flexible
  const categoriaLimpia = categoria.replace(/_/g, '');
  const respuestaSinGuiones = respuestaLimpia.replace(/_/g, '');

  // Verificar coincidencia exacta primero
  if (respuestaLimpia === categoria) {
    categoriaFinal = categoria;
    break;
  }

  // Verificar coincidencia sin guiones
  if (respuestaSinGuiones === categoriaLimpia) {
    categoriaFinal = categoria;
    break;
  }

  // Verificar si la categoría está contenida en la respuesta
  if (respuestaLimpia.includes(categoria)) {
    categoriaFinal = categoria;
    break;
  }
}

// Si no se encontró ninguna categoría válida, usar valor por defecto
if (!categoriaFinal) {
  // Intenta detectar palabras clave para asignar categoría más probable
  const palabrasClave = {
    'agendar_cita': ['agendar', 'cita', 'reunion', 'programar', 'apartar'],
    'cancelar_cita': ['cancelar', 'eliminar', 'borrar'],
    'posponer_cita': ['posponer', 'despues', 'pendiente'],
    'reagendar_cita': ['reagendar', 'cambiar', 'mover', 'reprogramar'],
    'conocer_servicios': ['conocer', 'servicios', 'informacion', 'que'],
    'comprar': ['comprar', 'precio', 'costo', 'contratar', 'cotizacion'],
    'asesoria_de_ventas': ['asesoria', 'ayuda', 'recomienda', 'conviene']
  };

  for (const [categoria, palabras] of Object.entries(palabrasClave)) {
    if (palabras.some(palabra => respuestaLimpia.includes(palabra))) {
      categoriaFinal = categoria;
      break;
    }
  }

  // Si aún no hay categoría, usar fallback
  if (!categoriaFinal) {
    categoriaFinal = 'conocer_servicios'; // Fallback más genérico
  }
}

// Registro para debugging (opcional, comentar en producción)
console.log('Respuesta original:', respuestaAgente);
console.log('Respuesta limpia:', respuestaLimpia);
console.log('Categoría final:', categoriaFinal);

// Retornar solo la categoría válida
return {
  json: {
    categoria: categoriaFinal,
    respuesta_original: respuestaAgente,
    es_valida: categoriasValidas.includes(categoriaFinal),
    timestamp: new Date().toISOString()
  }
};

