const agentOutput = $input.first().json.output;

// ====================================
// OBTENER FECHAS DE BASE DE DATOS - DESDE MERGE
// ====================================
let fechaCitaDatabase = "";
let fechaCitaTimezoneDatabase = "";

try {
  const inputData = $input.first().json;
  // Las fechas vienen directamente del merge (no del output del agente)
  // Estas son las fechas ORIGINALES de la base de datos
  fechaCitaDatabase = inputData.fecha_cita || "";
  fechaCitaTimezoneDatabase = inputData.fecha_cita_timezone_cliente || "";
} catch (e) {
