  const fechaCitaTimezoneLegibleDatabase = formatearFechaLegible(fechaCitaTimezoneDatabase, timeZone);

  return [{
    json: {
      // Originales
      respuesta: jsonData.respuesta || "",
      estado: jsonData.estado || "null",
      servicio: jsonData.servicio || "null",
      fecha_cita: jsonData.fecha_cita || "null",
      fecha_cita_timezone_cliente: jsonData.fecha_cita_timezone_cliente || "null",
      enlace_reunion: jsonData.enlace_reunion || "null",
      empresa: jsonData.empresa || "null",
