      nombre: nombre,
      pais: pais,
      motivo_cancelacion: jsonData.motivo_cancelacion || "",
      nuevo_google_event_id: jsonData.nuevo_google_event_id || "",

      // Normalizados
      nombre_normalizado: nombreNormalizado,
