// ====================================
// PARSER AGENTE DE TRANSICIÓN - SOCIALMASK
// Parsea output del agente Santiago (transición)
// Soporta TODOS los formatos posibles de JSON
// Campos: respuesta, escalamiento, agendar
// ====================================

const agentOutput = $input.first().json.output;

// ====================================
// FUNCIONES DE EXTRACCIÓN Y PARSING
// ====================================

/**
 * Extrae JSON del output con múltiples estrategias
 * Maneja todos los formatos incluyendo JSON malformado
 */
function extraerJSON(output) {
  if (!output) return null;

  let texto = output.trim();

  // ========================================
  // ESTRATEGIA 1: Buscar JSON entre llaves
  // ========================================
  const inicioJSON = texto.indexOf('{');
  const finJSON = texto.lastIndexOf('}');

  if (inicioJSON !== -1 && finJSON !== -1 && finJSON > inicioJSON) {
    texto = texto.substring(inicioJSON, finJSON + 1);
  }

  // ========================================
  // ESTRATEGIA 2: Limpiar prefijos markdown
  // ========================================
  texto = texto.replace(/^```json\s*/i, '');
  texto = texto.replace(/^```\s*/, '');
  texto = texto.replace(/\s*```$/g, '');
  texto = texto.replace(/^json[\s\n]*/i, '');

  // ========================================
  // ESTRATEGIA 3: Limpiar texto después del JSON
  // ========================================
  const ultimaLlave = texto.lastIndexOf('}');
  if (ultimaLlave !== -1 && ultimaLlave < texto.length - 1) {
    texto = texto.substring(0, ultimaLlave + 1);
  }

  // ========================================
  // ESTRATEGIA 4: Manejo de strings escapados
  // ========================================
  if (texto.startsWith('"') && texto.endsWith('"')) {
    try {
      texto = JSON.parse(texto);
    } catch (e) {
      texto = texto.slice(1, -1);
    }
  }

  // ========================================
  // ESTRATEGIA 5: Intentar parsear
  // ========================================
  try {
    return JSON.parse(texto);
  } catch (error) {
    return repararJSON(texto);
  }
}

/**
 * Repara JSON malformado
 */
function repararJSON(textoJSON) {
  try {
    let reparado = textoJSON.trim();

    // Contar llaves
    const aperturas = (reparado.match(/{/g) || []).length;
    const cierres = (reparado.match(/}/g) || []).length;

    // Agregar llaves faltantes
    if (aperturas > cierres) {
      const faltantes = aperturas - cierres;
      reparado += '}'.repeat(faltantes);
    }

    return JSON.parse(reparado);
  } catch (error) {
    return null;
  }
}

/**
 * Normaliza valor booleano de strings
 */
function normalizarBooleano(valor) {
  if (typeof valor === 'boolean') return valor;
  if (valor === null || valor === undefined) return false;

  const valorString = String(valor).toLowerCase().trim();

  // True: "true", "1", "yes", "sí", "si"
  if (['true', '1', 'yes', 'sí', 'si'].includes(valorString)) {
    return true;
  }

  // False: todo lo demás
  return false;
}

/**
 * Limpia y formatea la respuesta al cliente
 */
function limpiarRespuesta(respuesta) {
  if (!respuesta) return "";

  return String(respuesta)
    .replace(/\\n/g, '\n')    // Convertir \n en saltos de línea reales
    .replace(/\\"/g, '"')      // Quitar escapes de comillas
    .replace(/\\\\/g, '\\')    // Quitar escapes de backslashes
    .trim();
}

/**
 * Extrae campos del JSON parseado con valores por defecto
 */
function extraerCampos(jsonData) {
  if (!jsonData || typeof jsonData !== 'object') {
    return {
      respuesta: "",
      escalamiento: false,
      agendar: false,
      eliminar_cliente: false
    };
  }

  return {
    respuesta: limpiarRespuesta(jsonData.respuesta || ""),
    escalamiento: normalizarBooleano(jsonData.escalamiento),
    agendar: normalizarBooleano(jsonData.agendar),
    eliminar_cliente: normalizarBooleano(jsonData.eliminar_cliente)
  };
}

/**
 * Extrae respuesta del texto plano si el JSON falla completamente
 */
function extraerRespuestaFallback(output) {
  try {
    // Buscar el campo "respuesta" en el texto
    const match = output.match(/"respuesta"\s*:\s*"([^"]+(?:\\.[^"]+)*)"/);
    if (match && match[1]) {
      return limpiarRespuesta(match[1]);
    }

    // Si no encuentra, intentar buscar entre comillas después de "respuesta"
    const match2 = output.match(/respuesta["\s:]+([^,}]+)/i);
    if (match2 && match2[1]) {
      return limpiarRespuesta(match2[1].replace(/["']/g, ''));
    }
  } catch (e) {
    // Si todo falla, retornar mensaje genérico
  }

  return "Error al procesar la respuesta del agente. Por favor, contacta al equipo de soporte.";
}

/**
 * Extrae valores booleanos del texto plano si el JSON falla
 */
function extraerBooleanoFallback(output, campo) {
  try {
    const regex = new RegExp(`"${campo}"\\s*:\\s*(true|false)`, 'i');
    const match = output.match(regex);
    if (match && match[1]) {
      return normalizarBooleano(match[1]);
    }
  } catch (e) {
    // Ignorar error
  }
  return false;
}

// ====================================
// PROCESAMIENTO PRINCIPAL
// ====================================

try {
  // Intentar extraer y parsear el JSON
  const jsonData = extraerJSON(agentOutput);

  // Extraer campos con valores por defecto
  const campos = extraerCampos(jsonData);

  // Validación adicional: la respuesta no puede estar vacía
  if (!campos.respuesta || campos.respuesta.trim() === "") {
    // Intentar extraer del texto plano
    campos.respuesta = extraerRespuestaFallback(agentOutput);

    // Si aún está vacío, usar mensaje de error
    if (!campos.respuesta || campos.respuesta.trim() === "") {
      campos.respuesta = "Error: El agente no generó una respuesta válida.";
    }
  }

  // Crear el item en el formato que n8n espera
  const newItem = {
    json: {
      // ===== CAMPOS PRINCIPALES =====
      respuesta: campos.respuesta,
      escalamiento: campos.escalamiento,
      agendar: campos.agendar,
      eliminar_cliente: campos.eliminar_cliente,

      // ===== METADATOS DE PROCESAMIENTO =====
      procesado_correctamente: true,
      json_reparado: jsonData === null,
      timestamp_procesamiento: new Date().toISOString(),

      // ===== FLAGS ADICIONALES =====
      requiere_atencion_humana: campos.escalamiento,
      cliente_listo_para_agendar: campos.agendar,
      cliente_solicita_eliminacion: campos.eliminar_cliente,

      // ===== INFORMACIÓN DE DEBUG (opcional) =====
      longitud_respuesta: campos.respuesta.length,
      output_original_length: agentOutput ? agentOutput.length : 0
    }
  };

  // Retornar como array - FORMATO CORRECTO PARA N8N
  return [newItem];

} catch (error) {
  // ========================================
  // ÚLTIMO RECURSO: Extraer del texto plano
  // ========================================

  let respuestaExtraida = extraerRespuestaFallback(agentOutput);
  let escalamientoExtraido = extraerBooleanoFallback(agentOutput, 'escalamiento');
  let agendarExtraido = extraerBooleanoFallback(agentOutput, 'agendar');
  let eliminarExtraido = extraerBooleanoFallback(agentOutput, 'eliminar_cliente');

  // Item de error con información detallada
  const errorItem = {
    json: {
      // ===== CAMPOS PRINCIPALES (con fallbacks) =====
      respuesta: respuestaExtraida,
      escalamiento: escalamientoExtraido,
      agendar: agendarExtraido,
      eliminar_cliente: eliminarExtraido,

      // ===== METADATOS DE ERROR =====
      procesado_correctamente: false,
      json_reparado: false,
      error_detalle: error.message,
      requiere_atencion_humana: true, // Siempre true en caso de error
      cliente_listo_para_agendar: agendarExtraido,
      cliente_solicita_eliminacion: eliminarExtraido,

      // ===== INFORMACIÓN DE DEBUG =====
      output_recibido_preview: agentOutput ? agentOutput.substring(0, 300) : "vacío",
      output_completo_length: agentOutput ? agentOutput.length : 0,
      timestamp_procesamiento: new Date().toISOString(),

      // ===== ALERTA =====
      alerta_sistema: "El agente no devolvió JSON válido. Se extrajeron valores por fallback."
    }
  };

  return [errorItem];
}

// ====================================
// NOTAS DE USO
// ====================================
/*
CAMPOS DE SALIDA:

  1. respuesta (string): 
     - Mensaje para enviar al cliente por WhatsApp
     - Nunca vacío (usa fallback si falla)

  2. escalamiento (boolean):
     - true: Requiere intervención humana
     - false: El agente puede continuar

  3. agendar (boolean):
     - true: Cliente aceptó agendar, enviar número del agente de agendamiento
     - false: Cliente aún no acepta agendar

  4. eliminar_cliente (boolean):
     - true: Cliente confirmó eliminar su información y no ser contactado
     - false: Cliente no solicitó eliminación

FLUJO RECOMENDADO EN N8N:

  → IF (eliminar_cliente === true)
    ↳ Eliminar prospecto de base de datos
    ↳ Agregar a lista de no contactar
    ↳ Enviar respuesta de despedida al cliente
    ↳ TERMINAR flujo

  → IF (escalamiento === true)
    ↳ Enviar alerta a equipo humano
    ↳ Pausar automatización

  → IF (agendar === true)
    ↳ Enviar respuesta con número +523114862661
    ↳ Marcar lead como "En agendamiento"
    ↳ Notificar al Agente de Agendamiento

  → IF (agendar === false && escalamiento === false && eliminar_cliente === false)
    ↳ Continuar conversación automatizada
    ↳ Enviar respuesta al cliente
    ↳ Esperar siguiente mensaje

PRIORIDAD DE ACCIONES:
  1. eliminar_cliente (más alta prioridad - acción inmediata)
  2. escalamiento (segunda prioridad - intervención humana)
  3. agendar (tercera prioridad - transición a agendamiento)
  4. continuar conversación (default)

MANEJO DE ERRORES:

  - Si procesado_correctamente === false:
    → Revisar output_recibido_preview
    → Escalar a humano automáticamente
    → Verificar que el agente está devolviendo JSON correcto

  - Si json_reparado === true:
    → El JSON tenía problemas pero se reparó
    → Funcional pero revisar logs
    → Considerar mejorar el prompt del agente

  - Si alerta_sistema existe:
    → Error crítico en el parsing
    → Se usaron fallbacks
    → Requiere revisión manual
*/

